#!/usr/bin/env bash
CASE_TYPE=$1
pushd ccd-definition-processor yarn xlsx2json -D ../definitions/$CASE_TYPE/json -i ../definitions/$CASE_TYPE/xlsx/ccd-$CASE_TYPE-config-base.xlsx && popd && pretty-quick --pattern '$CASE_TYPE/**/json/**.json' && sed -e 's+http://ia-case-api:8090+${CCD_DEF_IA_URL}+g' ./definitions/$CASE_TYPE/json/CaseEvent.json  > ./definitions/$CASE_TYPE/json/CaseEvent.json.new && mv ./definitions/$CASE_TYPE/json/CaseEvent.json.new ./definitions/$CASE_TYPE/json/CaseEvent.json && mv definitions/$CASE_TYPE/json/UserProfile.json definitions/$CASE_TYPE/env/${CCD_ENV:-dev}/UserProfile.json
